+/// Observation record for sliding window
+#[derive(Debug, Clone, Copy, Default)]
+#[repr(C)]
+pub struct ObsRecord {
+    /// Observation data
+    pub obs: Observation,
+    /// Timestamp (tick)
+    pub tick: u32,
+}
