+        let entry = &mut self.vertices[v as usize];
+        if entry.is_active() {
+            return false; // Already active
+        }
+
+        entry.flags = VertexEntry::FLAG_ACTIVE;
+        entry.degree = 0;
+        entry.component = 0;
+        entry.first_edge_idx = 0xFFFF;
+        self.num_vertices += 1;
+        self.status |= Self::STATUS_DIRTY;
