+    /// The adjacency scan is a hot path in graph algorithms.
+    #[inline]
+    pub fn find_edge(&self, source: TileVertexId, target: TileVertexId) -> Option<TileEdgeId> {
+        if source as usize >= MAX_SHARD_VERTICES {
+            return None;
+        }
